// Curried add
const add = (a) => (b) => a + b;
const add5 = add(5);
console.log(add5(3)); // 8

const compose = (f, g) => (x) => f(g(x));
const double = (x) => x * 2;
const inc = (x) => x + 1;
const doubleThenInc = compose(inc, double);
console.log(doubleThenInc(3)); // 7

function makeCounter() {
  let count = 0;
  return () => ++count;
}
const counter = makeCounter();
console.log(counter()); // 1
console.log(counter()); // 2
